import{c as o,Q as t,j as r,m as a}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"SOP Operational Guides","description":"Standard Operating Procedures (SOP) for starting, configuring, and debugging the orchestrator system","frontmatter":{"title":"SOP Operational Guides","description":"Standard Operating Procedures (SOP) for starting, configuring, and debugging the orchestrator system","keywords":"SOP, runbook, operational guide, setup protocol, troubleshooting guide","robots":"index, follow"},"headers":[],"relativePath":"en/sop/index.md","filePath":"en/sop/index.md","lastUpdated":null}'),i={name:"en/sop/index.md"};function s(n,e,l,d,u,g){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="📋-sop-operational-guides" tabindex="-1">📋 SOP Operational Guides <a class="header-anchor" href="#📋-sop-operational-guides" aria-label="Permalink to &quot;📋 SOP Operational Guides&quot;">​</a></h1><p>Welcome to the <strong>Standard Operating Procedures (SOP)</strong> index. This section houses detailed operational runbooks designed for Site Reliability Engineers (SREs) and system administrators responsible for operating and scaling the <strong>AI Workflow Orchestrator</strong>.</p><hr><h2 id="🗂️-operational-runbook-directory" tabindex="-1">🗂️ Operational Runbook Directory <a class="header-anchor" href="#🗂️-operational-runbook-directory" aria-label="Permalink to &quot;🗂️ Operational Runbook Directory&quot;">​</a></h2><p>Our guides are separated into two distinct focus areas:</p><h3 id="_1-sop-001-installation-setup-guide" tabindex="-1">1. <a href="/en/sop/setup">SOP-001: Installation &amp; Setup Guide</a> <a class="header-anchor" href="#_1-sop-001-installation-setup-guide" aria-label="Permalink to &quot;1. [SOP-001: Installation &amp; Setup Guide](/en/sop/setup)&quot;">​</a></h3><p>Step-by-step instructions for booting the environment, binding API keys, setting up databases, and enforcing zero-trust boundaries.</p><ul><li><strong>Topics covered:</strong> API key rotation schemas, session token budgeting, MongoDB Atlas vector configuration, and sandbox environments verification.</li><li><strong>Status:</strong> 🟢 Active &amp; Verified.</li></ul><h3 id="_2-sop-002-diagnostics-troubleshooting-guide" tabindex="-1">2. <a href="/en/sop/troubleshooting">SOP-002: Diagnostics &amp; Troubleshooting Guide</a> <a class="header-anchor" href="#_2-sop-002-diagnostics-troubleshooting-guide" aria-label="Permalink to &quot;2. [SOP-002: Diagnostics &amp; Troubleshooting Guide](/en/sop/troubleshooting)&quot;">​</a></h3><p>Runbooks for recovering from system errors, repairing corrupt database files, resolving connection drops, and analyzing runtime trace logs.</p><ul><li><strong>Topics covered:</strong> Resetting agent ELO ratings, SQLite file recovery, debugging budget trips, and intercepting self-healing logs inside the <code>storage/traces/</code> directory.</li><li><strong>Status:</strong> 🟢 Active &amp; Verified.</li></ul><hr><h2 id="🛡️-core-rules-for-system-operators" tabindex="-1">🛡️ Core Rules for System Operators <a class="header-anchor" href="#🛡️-core-rules-for-system-operators" aria-label="Permalink to &quot;🛡️ Core Rules for System Operators&quot;">​</a></h2><p>Before initiating any manual terminal command or configuration change, adhere to the following safety policies:</p><ol><li><strong>Never hardcode secrets:</strong> All sensitive resources (such as Google API keys or MongoDB URIs) must be injected as encrypted environment variables or loaded from secret stores (e.g. GCP Secret Manager).</li><li><strong>Back up databases before rating updates:</strong> Any manual ELO reputation adjust operations must be preceded by an offline file backup (<code>cp storage/memory.db storage/memory_backup.db</code>).</li><li><strong>Inspect Critic traces before manual intervention:</strong> Always analyze trace summaries of failed workflow runs to leverage the Critic agent&#39;s automated diagnosis before building manual hotfixes.</li></ol>',15)])])}const h=o(i,[["render",s]]);export{p as __pageData,h as default};
